// ========================================
// EJEMPLO DE CODE NODE EN N8N
// ========================================

// 1. Obtener los datos del nodo anterior
const datos = $input.first().json;

// 2. Crear variables con los datos
const nombre = datos.nombre;
const edad = datos.edad;
const descuento = datos.descuento;

// 3. Hacer transformaciones
const nombreMayusculas = nombre.toUpperCase();
const edadEnMeses = edad * 12;
const precioFinal = 100 - (100 * descuento / 100);

// 4. Crear un mensaje personalizado
const resumen = `
📊 RESUMEN DEL USUARIO
━━━━━━━━━━━━━━━━━━━━━
👤 Nombre: ${nombreMayusculas}
🎂 Edad: ${edad} años (${edadEnMeses} meses)
💰 Descuento: ${descuento}%
🏷️ Precio final: $${precioFinal}
━━━━━━━━━━━━━━━━━━━━━
`;

// 5. SIEMPRE devolver un array con objetos json
return [{
  json: {
    ...datos,  // Mantener datos anteriores
    nombre_mayusculas: nombreMayusculas,
    edad_en_meses: edadEnMeses,
    precio_final: precioFinal,
    resumen: resumen,
    procesado_con_code: true
  }
}];

