// Recibimos los datos del nodo anterior
const datos = $input.first().json;

// Creamos un resumen
const resumen = {
  mensaje_final: `🌟 ${datos.usuario} es nivel ${datos.nivel}`,
  puntos_dobles: datos.puntos * 2,
  fecha_proceso: new Date().toLocaleString('es-ES'),

  // Mantenemos datos originales
  datos_originales: datos
};

// SIEMPRE retornamos [{json: {...}}]
return [{json: resumen}];
